scwin.alignMenuTreeOptions = function () {
  try {
    tv_menu.options.hierarchy = true;
    tv_menu.options.showTreeDepth = "0";
    tv_menu.options.toggleEvent = "onclick";
  } catch (e) {}
};
scwin.filterSubCompanyNcallMenu = function (menuList) {
  debugger;
  if (scwin.coClsCd == "0" || scwin.coClsCd == "") {
    return menuList || [];
  }
  return (menuList || []).filter(function (menu) {
    const menuId = (menu && menu.menuId || "").toLowerCase();
    const menuNm = menu && menu.menuNm || "";
    return menuId.indexOf("n") === -1 && menuNm.indexOf("엔콜") === -1;
  });
};
scwin.menuTreeSearchSnapshot = [];
scwin.menuTreeSearchInProgress = false;
scwin.cloneMenuTreeList = function (menuList) {
  try {
    return JSON.parse(JSON.stringify(menuList || []));
  } catch (e) {
    return (menuList || []).slice();
  }
};
scwin.setMenuTreeSearchSource = function (menuList) {
  scwin.menuTreeSearchSnapshot = scwin.cloneMenuTreeList(menuList);
};
scwin.normalizeMenuTreeSearchText = function (value) {
  return String(value || "").replace(/\s+/g, "").toLowerCase();
};
scwin.getMenuTreeSearchSource = function () {
  if ((scwin.menuTreeSearchSnapshot || []).length > 0) {
    return scwin.menuTreeSearchSnapshot;
  }
  return ds_menuList.getAllJSON() || [];
};
scwin.searchMenuTreeLocal = function (keyword) {
  const sourceMenuList = scwin.getMenuTreeSearchSource();
  const normalizedKeyword = scwin.normalizeMenuTreeSearchText(keyword);
  if (!normalizedKeyword || sourceMenuList.length === 0) {
    return [];
  }
  const menuMap = {};
  const includedMenuMap = {};
  for (const row of sourceMenuList) {
    menuMap[row.menuId] = row;
  }
  const includeAncestors = function (menuId) {
    let currentMenuId = menuId;
    while (currentMenuId && menuMap[currentMenuId]) {
      if (includedMenuMap[currentMenuId]) {
        break;
      }
      includedMenuMap[currentMenuId] = true;
      currentMenuId = menuMap[currentMenuId].upperMenuId || "";
    }
  };
  for (let index = 0; index < sourceMenuList.length; index++) {
    const row = sourceMenuList[index];
    const actPgmId = String(row.actPgmId || "").trim();
    if (!actPgmId) {
      continue;
    }
    const searchTarget = scwin.normalizeMenuTreeSearchText([row.menuNm, row.actPgmNm, row.actPgmId].join(" "));
    if (searchTarget.indexOf(normalizedKeyword) > -1) {
      includedMenuMap[row.menuId] = true;
      includeAncestors(row.menuId);
    }
  }
  return sourceMenuList.filter(function (row) {
    return !!includedMenuMap[row.menuId];
  });
};
scwin.applyMenuTreeSearchResult = function (menuList) {
  ds_menuList.setJSON(menuList || []);
  try {
    scwin.alignMenuTreeOptions();
    tv_menu.spanAll(true);
  } catch (e) {}
};
scwin.normalizeRetrievedMenuList = function (menuArray) {
  menuArray = scwin.cloneMenuTreeList(menuArray);
  for (const row of menuArray) {
    switch (row.actPgmId) {
      case "op_304_01_01b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "op_304_01_02b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "as_102_01_02b.jsp":
        row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
        break;
      case "as_102_01_03b.jsp":
        row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
        break;
      case "op_301_01_05b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_19b.jsp";
        }
        break;
      case "op_301_01_06b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_09b.jsp";
        }
        break;
      case "op_304_01_06b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "fs_103_03_01b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "fs_103_03_02b.jsp";
        }
        break;
      case "op_204_04_01b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
          row.actPgmId = "tn_304_03_09b.jsp";
        }
        break;
      case "op_301_01_17b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_20b.jsp";
        }
        break;
      case "op_304_01_65b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
          row.actPgmId = "tn_304_01_12b.jsp";
        }
        break;
      case "op_202_02_07b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_202_02_08b.jsp";
        }
        break;
      case "sd_402_01_35t.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "sd_402_01_35b.jsp";
        }
        break;
    }
  }
  return scwin.filterSubCompanyNcallMenu(menuArray);
};
scwin.restoreMenuTreeSearchResult = function () {
  ds_menuList.setJSON(scwin.getMenuTreeSearchSource());
};
scwin.searchMenuTree = async function (value) {
  const searchKeyword = String(value || "").trim();
  if (!searchKeyword) {
    scwin.restoreMenuTreeSearchResult();
    return;
  }
  dma_search.set("menuNm", searchKeyword);
  scwin.menuTreeSearchInProgress = true;
  $c.sbm.execute($p, sbm_menuList);
};
scwin.ibx_menuTreeSearch_oneditkeyup = function (info) {
  if (info.keyCode == 13) {
    scwin.searchMenuTree(info.newValue);
  }
};
scwin.btn_menuTreeSearch_onclick = function () {
  scwin.searchMenuTree(ibx_menuTreeSearch.getValue());
};
scwin.f_Retrieve = function () {
  dma_search.set("sysCd", "");
  dma_search.set("menuNm", "");
  if (scwin.memJson.coCd === "000") {
    dma_search.set("coCd", "tobe");
  } else if (scwin.memJson.coCd === "") {
    dma_search.set("coCd", scwin.memJson.coCd);
  } else if (scwin.memJson.coCd === "017") {
    dma_search.set("coCd", "tobe017");
  } else {
    dma_search.set("coCd", "tobeCompany");
  }
  $c.sbm.execute($p, sbm_menuList);
  dma_search.set("userId", scwin.userId);
  $c.sbm.execute($p, sbm_mymenu);
};
scwin.sbm_menuList_submitdone = async function (e) {
  const menuArray = scwin.normalizeRetrievedMenuList(e.responseJSON && e.responseJSON.GAUCE || []);
  if (scwin.menuTreeSearchInProgress) {
    scwin.menuTreeSearchInProgress = false;
    dma_search.set("menuNm", "");
    if (menuArray.length === 0) {
      const localMenuList = scwin.searchMenuTreeLocal(ibx_menuTreeSearch.getValue());
      if (localMenuList.length > 0) {
        scwin.applyMenuTreeSearchResult(localMenuList);
        return;
      }
      await $c.win.alert($p, "조회된 데이터가 없습니다.");
      scwin.restoreMenuTreeSearchResult();
      return;
    }
    scwin.applyMenuTreeSearchResult(menuArray);
    return;
  }
  ds_menuList.setJSON(menuArray);
  scwin.setMenuTreeSearchSource(menuArray);
};
scwin.sbm_mymenu_submitdone = async function () {
  ds_mymenu.setJSON(scwin.filterSubCompanyNcallMenu(ds_mymenu.getAllJSON()));
  var x = 0;
  for (var i = 0; i < ds_mymenu.getTotalRow(); i++) {
    var grpNmExists = false;
    var irow = ds_mymenu.getRowJSON(i);
    for (var j = 0; j < ds_menuGrpNm.getTotalRow(); j++) {
      var jrow = ds_menuGrpNm.getRowJSON(j);
      if (irow.menuGrpNm == jrow.code) {
        grpNmExists = true;
      }
    }
    if (!grpNmExists) {
      await ds_menuGrpNm.insertJSON(x++, [{
        code: irow.menuGrpNm,
        name: irow.menuGrpNm
      }]);
    }
  }
  $c.sbm.execute($p, sbm_mymenuList);
};
scwin.sbm_mymenuList_submitdone = async function (e) {
  ds_mymenuList.setJSON(scwin.filterSubCompanyNcallMenu(ds_mymenuList.getAllJSON()));
  // var rowCnt = ds_mymenuList.getRowCount();
  // spanTotal.setLabel(rowCnt);
  gr_mymenuList.setFocusedCell(0, 0);
};
